window.GIFT_ORDER = ["catalyst","servant","erudite","enthusiast","host","strategist","lover"];
window.GIFTS = {"catalyst":{"slug":"catalyst","name":"The Catalyst","subtitle":"The Gift of Prophecy","metaphor":{"title":"The Volcano","description":"The volcano represents the powerful, transformative force within the prophetically gifted—a divine fire that builds pressure beneath the surface until it erupts in truth-telling and catalytic change. The color Lava Red represents this molten intensity, symbolizing the heated passion for truth and the creative and destructive potential of the gift.","icon":"Flame"},"profileSummary":"The Catalyst is a visionary and pioneering force, driven by a need for truth and a passion for revolutionary transformation. This is not merely a personality trait but a sacred calling—a divine operational style that compels them to challenge the status quo, uproot broken systems, and build new, more effective ones in their place.","foundationalVerses":["Romans 12:6 - \"Having gifts that differ according to the grace given to us, let us use them: if prophecy, in proportion to our faith.\"","1 Thessalonians 5:21 - \"Test all things; hold fast what is good.\""],"descriptiveWords":["Innovative","Challenger","Assured","Discerning","Go-getting","Adventurous"],"coreFramework":{"question":"What is the truth that will unlock transformation here?","questionDescription":"The Catalyst instinctively searches for the foundational truth that, once revealed, will catalyze change. Where others see a simple conflict, the Catalyst sees a broken system and discerns the pathway to its renewal.","energizer":"Willingness to Confront Reality","energizerDescription":"Catalysts are energized by courage, not just comfort. They need to be surrounded by people willing to look at the brutal facts of a situation and act on them.","drive":"Transformation","driveDescription":"They are compelled to spark transformation and create breakthrough solutions, acting from a sense of eternal perspective while pioneering innovative approaches that revolutionize systems."},"strengths":[{"title":"Visionary Courage","description":"They possess a profound courage that enables them to speak truth to power and challenge entrenched systems that others avoid."},{"title":"Unwavering Integrity","description":"They are driven by an uncompromising commitment to integrity and an innate desire for alignment between words, actions, and motives."},{"title":"Passionate Conviction","description":"They operate from a place of deep, immovable conviction, giving them the resilience to stand for what is right, even in the face of opposition."},{"title":"Drive for Authentic Renewal","description":"Beyond simply pointing out flaws, their ultimate strength is a powerful vision for genuine renewal and the relentless drive to help build it."}],"challenges":[{"title":"A Tendency Toward Harsh Judgment","description":"Their high standards can cause them to judge others' perceived failures without sufficient grace."},{"title":"Impatience with Process","description":"Their breakneck desire for results can cause them to view other personalities as barriers to change."},{"title":"Emotional Burden and Isolation","description":"The constant awareness of what's wrong can create a heavy emotional burden, leading to cynicism and isolation if not balanced with grace."}],"leadershipStyle":{"title":"Catalytic Innovator","description":"Prophetic leaders lead through transformational vision and breakthrough thinking.","characteristics":["Disruptive Innovation","Catalytic Communication","Pioneering Spirit","Systems Transformation","Moral Courage"]},"interactions":["Be direct and willing to confront hard truths; they value courage over comfort.","Focus on the \"why\" behind a project, not just the \"what.\"","Give them problems to solve and a safe place to fail without judgment.","Don't be offended by their directness; understand it often comes from a desire to improve things."],"commission":"Jeremiah 1:10: \"See, today I appoint you over nations and kingdoms to uproot and tear down, to destroy and overthrow, to build and to plant.\""},"servant":{"slug":"servant","name":"The Servant of All","subtitle":"The Gift of Service","metaphor":{"title":"The Harvester","description":"The harvester represents the tireless, systematic work of gathering what has been planted. Like a combine harvester moving through fields with precision and endurance, those with the gift of service work with methodical excellence to meet practical needs and ensure nothing valuable is wasted.","icon":"Wrench"},"profileSummary":"The Servant of All possesses a divine compulsion to meet practical needs through tangible action and faithful work. They are the backbone of any organization, driven not by recognition but by the deep satisfaction of seeing tasks completed with excellence and people genuinely helped.","foundationalVerses":["Romans 12:7 - \"If it is serving, then serve; if it is teaching, then teach.\"","Mark 10:43-44 - \"Whoever wants to become great among you must be your servant, and whoever wants to be first must be slave of all.\""],"descriptiveWords":["Industrious","Hands-on","Consistent","Meticulous","Supportive","Conscientious"],"coreFramework":{"question":"What needs to be done, and who is doing it?","questionDescription":"The service-gifted are driven by an internal question that constantly scans their environment for practical needs and assesses whether everyone is contributing fairly.","energizer":"Visible Recognition & Shared Effort","energizerDescription":"They are energized when their practical contributions are specifically noticed and genuinely recognized, and they thrive when others step up to help.","drive":"Tangible Results","driveDescription":"They are driven by the deep satisfaction of completing a task, solving a practical problem, and seeing the high-quality result of their labor."},"strengths":[{"title":"Unwavering Dependability","description":"They possess a rare level of reliability that others can count on. When they commit to something, it gets done with excellence and on time."},{"title":"Excellence in Execution","description":"They have a natural drive for quality and attention to detail that ensures work is not just completed but completed well."},{"title":"Practical Problem-Solving","description":"They excel at finding practical, effective solutions to real-world problems and implementing them efficiently."},{"title":"Faithful Endurance","description":"They possess the perseverance to stick with tasks through completion, even when the work is difficult or unrecognized."}],"challenges":[{"title":"Tendency to Over-Commit","description":"Their desire to help can lead them to take on more than they can handle, resulting in burnout and resentment."},{"title":"Difficulty Saying No","description":"They may struggle to set healthy boundaries and prioritize their own needs when others are asking for help."},{"title":"Criticism of Others' Work Standards","description":"Their high standards for quality work can lead to frustration and criticism when others don't meet their expectations."}],"leadershipStyle":{"title":"Servant Leader","description":"Service leaders lead through humble example and dedicated support.","characteristics":["Leading by Example","Practical Problem-Solving","Supportive Infrastructure","Attention to Detail","Consistent Follow-Through"]},"interactions":["Appreciate their behind-the-scenes work and acknowledge their contributions.","Give them clear expectations and the resources they need to do excellent work.","Don't take advantage of their willingness to help; respect their time and energy.","Include them in planning so they understand how their work fits into the bigger picture."],"commission":"Mark 10:43-44: \"Whoever wants to become great among you must be your servant, and whoever wants to be first must be slave of all.\""},"erudite":{"slug":"erudite","name":"The Erudite","subtitle":"The Gift of Teaching","metaphor":{"title":"The Ancient Oak Tree","description":"The Ancient Oak represents the deep-rooted wisdom and enduring strength of the teaching gift. Like an oak that grows slowly but stands for centuries, those with the gift of teaching develop profound understanding over time and become sources of reliable wisdom for generations.","icon":"TreePine"},"profileSummary":"The Erudite carries a divine hunger for truth and understanding, called to learn with rigor and share knowledge with clarity. They are driven by an insatiable curiosity and a commitment to intellectual honesty that makes them trusted sources of wisdom and insight.","foundationalVerses":["Romans 12:7 - \"If it is serving, then serve; if it is teaching, then teach.\"","2 Timothy 2:15 - \"Study to show yourself approved to God, a worker who does not need to be ashamed and who correctly handles the word of truth.\""],"descriptiveWords":["Analytical","Thorough","Patient","Precise","Knowledgeable","Insightful"],"coreFramework":{"question":"Is this subject worthy of my intellectual energy?","questionDescription":"The Erudite filters the world through a lens of intellectual substance. Before investing their energy, they instinctively assess if a topic has sufficient depth and truth to justify the rigorous process of mastery.","energizer":"Deep Study & Genuine Curiosity from Others","energizerDescription":"They are energized by uninterrupted time for deep research and reflection. This energy is compounded when others show genuine curiosity and a sincere desire to learn what they have discovered.","drive":"To Acquire & Disseminate Knowledge","driveDescription":"They are driven by an insatiable desire to acquire a mastery-level understanding of complex subjects and feel a compulsion to disseminate that knowledge with clarity and precision."},"strengths":[{"title":"Intellectual Rigor","description":"They possess an exceptional commitment to thorough research and logical analysis that ensures their conclusions are well-founded and trustworthy."},{"title":"Patient Teaching Ability","description":"They have a natural gift for breaking down complex concepts and presenting them in ways that others can understand and apply."},{"title":"Commitment to Accuracy","description":"They are driven by a desire for precision and truth that makes them reliable sources of information and wisdom."},{"title":"Deep Curiosity","description":"They possess an insatiable hunger for learning that drives them to continuously expand their knowledge and understanding."}],"challenges":[{"title":"Analysis Paralysis","description":"Their desire for thoroughness can sometimes prevent them from taking action or making decisions in a timely manner."},{"title":"Impatience with Shallow Thinking","description":"They may become frustrated with others who don't share their commitment to intellectual rigor and deep analysis."},{"title":"Tendency to Intellectualize Emotions","description":"They may struggle to connect with others on an emotional level, preferring logical analysis over emotional processing."}],"leadershipStyle":{"title":"The Wise Teacher","description":"Erudite leaders lead through wisdom, clarity, and the intellectual development of their team. They don't just give answers; they teach people how to think.","characteristics":["Mentoring Focus","Clarity of Communication","Evidence-Based Decisions","Fostering a Learning Culture","Principled Guidance"]},"interactions":["Respect their need for time to think and research before making decisions.","Value their expertise and seek their input on complex matters.","Don't rush them into quick decisions; they need time to analyze properly.","Appreciate their commitment to accuracy and thoroughness."],"commission":"Matthew 28:19-20: \"Go therefore and make disciples of all nations... teaching them to observe all that I have commanded you.\""},"enthusiast":{"slug":"enthusiast","name":"The Enthusiast","subtitle":"The Gift of Encouragement","metaphor":{"title":"The Magnet","description":"The magnet represents the natural ability to attract and connect people through positive energy and genuine care. Like a magnet that draws metal filings into alignment, those with the gift of encouragement have a remarkable ability to draw people together and align them toward common goals.","icon":"Users"},"profileSummary":"The Enthusiast operates under a divine mandate to champion the potential in others and foster meaningful connections. They are natural connectors and motivators, driven by a genuine love for people and an unshakeable belief in their capacity to grow and succeed.","foundationalVerses":["Romans 12:8 - \"If it is to encourage, then give encouragement.\"","1 Thessalonians 5:11 - \"Therefore encourage one another and build each other up, just as in fact you are doing.\""],"descriptiveWords":["Enthusiastic","Rallying","Expressive","Affirming","Motivational","Interpersonal"],"coreFramework":{"question":"Are we building a bond?","questionDescription":"The Enthusiast constantly assesses the quality of relational connection, believing that authentic connection is the foundation for all positive growth.","energizer":"Heartfelt Connection & Shared Joy","energizerDescription":"They are energized by moments of authentic connection—shared laughter, meaningful conversation, and mutual celebration.","drive":"To Rally","driveDescription":"They are driven by an innate ability to rally people together around a shared purpose or possibility, turning individual potential into group momentum."},"strengths":[{"title":"Natural Motivational Ability","description":"They possess an extraordinary gift for inspiring others and helping them believe in their own potential and possibilities."},{"title":"Relationship Building","description":"They excel at creating meaningful connections between people and fostering environments of trust and collaboration."},{"title":"Positive Energy","description":"They bring an infectious optimism and enthusiasm that lifts the spirits of those around them and creates positive momentum."},{"title":"Ability to See Potential","description":"They have a remarkable ability to see the best in people and help them recognize and develop their own gifts and capabilities."}],"challenges":[{"title":"Avoiding Difficult Conversations","description":"Their desire to maintain positive relationships can lead them to avoid necessary but challenging conversations."},{"title":"Over-Optimism","description":"Their positive outlook can sometimes lead them to overlook real problems or minimize legitimate concerns."},{"title":"People-Pleasing Tendencies","description":"They may struggle to set boundaries or make decisions that might disappoint others, even when those decisions are necessary."}],"leadershipStyle":{"title":"Inspirational Motivator","description":"Enthusiast leaders lead through inspiration and empowerment.","characteristics":["Vision Casting","Strength-Based Development","Positive Culture Creation","Recognition and Celebration","Coaching and Mentoring","Empowerment"]},"interactions":["Appreciate their efforts to maintain positive relationships and team morale.","Help them balance optimism with realistic assessment of challenges.","Support them in having difficult conversations when necessary.","Value their ability to see potential in others and build strong teams."],"commission":"Hebrews 10:24: \"And let us consider how we may spur one another on toward love and good deeds.\""},"host":{"slug":"host","name":"The Host","subtitle":"The Gift of Giving","metaphor":{"title":"The Silo","description":"The silo represents the strategic storage and distribution of resources for maximum impact. Like a grain silo that preserves harvest abundance for future seasons, those with the gift of giving understand how to steward resources wisely and release them strategically for the greatest benefit.","icon":"Building"},"profileSummary":"The Host understands that all resources are entrusted to them for the benefit of others through strategic stewardship. They are driven not by accumulation but by multiplication—finding ways to use what they have been given to empower others and create sustainable impact.","foundationalVerses":["Romans 12:8 - \"If it is giving, then give generously.\"","Luke 6:38 - \"Give, and it will be given to you. A good measure, pressed down, shaken together and running over, will be poured into your lap. For with the measure you use, it will be measured to you.\""],"descriptiveWords":["Generous","Multiplier","Hospitable","Prudent","Empowering","Abundant"],"coreFramework":{"question":"How are we stewarding our resources?","questionDescription":"The Host constantly evaluates how they and others are managing what they've been entrusted with, assessing whether resources are being used wisely and strategically.","energizer":"Fruitful Impact & Expressed Gratitude","energizerDescription":"Hosts are energized when they see their resources making a real, tangible difference in others' lives and when their thoughtful giving is met with genuine gratitude.","drive":"To Steward & Multiply","driveDescription":"They are driven to create, manage, and multiply resources so they can give more generously and effectively, and to help others become good stewards as well."},"strengths":[{"title":"Strategic Generosity","description":"They possess an exceptional ability to give in ways that create maximum impact and empower others to succeed and give in return."},{"title":"Resource Wisdom","description":"They have a natural understanding of how to manage, preserve, and multiply resources for long-term benefit rather than short-term gratification."},{"title":"Empowerment Focus","description":"They excel at using their resources to empower others, creating opportunities for people to develop their own capabilities and become successful."},{"title":"Multiplication Mindset","description":"They think in terms of creating systems and opportunities that multiply impact rather than simply meeting immediate needs."}],"challenges":[{"title":"Tendency to Control Outcomes","description":"Their strategic approach to giving can sometimes lead them to try to control how their gifts are used rather than trusting the recipients."},{"title":"Difficulty with Spontaneous Giving","description":"Their preference for strategic planning can make it challenging for them to respond to immediate, unplanned needs with flexibility."},{"title":"Judgment of Poor Stewardship","description":"They may become frustrated with others who don't share their commitment to wise resource management and strategic thinking."}],"leadershipStyle":{"title":"The Steward Leader","description":"Host leaders lead through resource provision and strategic investment.","characteristics":["Resource Provision","Strategic Investment","Opportunity Creation","Welcoming Culture","Empowerment Focus","Stewardship Modeling"]},"interactions":["Respect their desire to understand how resources will be used before committing.","Show them the long-term impact and multiplication potential of projects.","Don't pressure them for immediate decisions; they need time to consider strategic implications.","Appreciate their commitment to wise stewardship and empowerment of others."],"commission":"Acts 20:35: \"It is more blessed to give than to receive.\""},"strategist":{"slug":"strategist","name":"The Strategist","subtitle":"The Gift of Leadership","metaphor":{"title":"The Ship's Helm","description":"The ship's helm represents the steady, purposeful guidance that keeps an organization moving toward its destination despite changing winds and currents. Like a skilled helmsman who reads both the immediate conditions and the distant horizon, those with the gift of leadership navigate toward long-term vision while managing present realities.","icon":"Compass"},"profileSummary":"The Strategist carries a divine capacity to see future possibilities and architect the systems required to make them reality. They are natural visionaries and systematic builders, driven by the ability to envision what could be and the determination to create the pathways to achieve it.","foundationalVerses":["Romans 12:8 - \"If it is to lead, do it diligently.\"","Proverbs 29:18 - \"Where there is no vision, the people perish.\""],"descriptiveWords":["Decisive","Goal-oriented","Authoritative","Systematic","Developmental","Architectural"],"coreFramework":{"question":"Where are we going, and what is the best way to get there?","questionDescription":"The Strategist sees the world through a lens of vision and execution, instinctively assessing the ultimate goal and then architecting the most effective path to achieve it.","energizer":"Team Alignment & Measurable Progress","energizerDescription":"They are energized when the team is aligned with the vision and working together cohesively. Seeing measurable progress toward clear objectives fuels their drive.","drive":"To Architect Success","driveDescription":"They are compelled to provide direction, create order from chaos, and build systems that produce sustainable excellence, developing people and frameworks that succeed long-term."},"strengths":[{"title":"Visionary Thinking","description":"They possess an exceptional ability to envision future possibilities and see the big picture in ways that others cannot."},{"title":"Systems Architecture","description":"They excel at designing and implementing systematic approaches that turn visions into achievable, step-by-step realities."},{"title":"Strategic Decision-Making","description":"They have a natural ability to make decisions that align with long-term objectives rather than just addressing immediate concerns."},{"title":"Development of Others","description":"They are gifted at recognizing potential in others and creating opportunities for people to grow and contribute to larger objectives."}],"challenges":[{"title":"Impatience with Details","description":"Their focus on big-picture vision can sometimes lead them to overlook important details or become impatient with necessary but mundane tasks."},{"title":"Tendency to Overwhelm Others","description":"Their ambitious visions and systematic approaches can sometimes feel overwhelming or unrealistic to others who don't share their strategic perspective."},{"title":"Difficulty with Immediate Needs","description":"Their long-term focus can make it challenging for them to respond effectively to immediate, urgent needs that don't fit into their strategic plans."}],"leadershipStyle":{"title":"Strategic Architect","description":"Strategist leaders lead through vision, planning, and systematic execution.","characteristics":["Visionary Planning","Strategic Thinking","System Building","Team Development","Goal Achievement"]},"interactions":["Respect their need to understand how immediate tasks fit into the bigger picture.","Support their long-term thinking and don't pressure them for quick fixes to complex problems.","Help them communicate their vision in ways that others can understand and embrace.","Appreciate their commitment to systematic development and sustainable growth."],"commission":"Proverbs 29:18: \"Where there is no vision, the people perish; but blessed is he who keeps the law.\""},"lover":{"slug":"lover","name":"The Lover","subtitle":"The Gift of Mercy","metaphor":{"title":"The Heart","description":"The heart represents the life-giving center of compassion and emotional healing. Like the physical heart that pumps life-sustaining blood throughout the body, those with the gift of mercy circulate love, empathy, and healing throughout their communities, bringing emotional health and restoration.","icon":"Heart"},"profileSummary":"The Lover carries a divine heart that beats with compassion for the suffering and wounded, bringing healing presence wherever pain exists. They are natural empaths and healers, driven by an overwhelming desire to comfort, protect, and restore those who are hurting.","foundationalVerses":["Romans 12:8 - \"If it is to show mercy, do it cheerfully.\"","2 Corinthians 1:3-4 - \"Praise be to the God and Father of our Lord Jesus Christ, the Father of compassion and the God of all comfort, who comforts us in all our troubles, so that we can comfort those in any trouble with the comfort we ourselves receive from God.\""],"descriptiveWords":["Empathetic","Accepting","Nurturing","Rescuing","Gentle","Patient"],"coreFramework":{"question":"Is this a safe place for the heart?","questionDescription":"The Lover constantly assesses the emotional climate of their surroundings, driven to create environments where hearts can be vulnerable without fear of judgment.","energizer":"Emotional Safety & Unconditional Acceptance","energizerDescription":"Lovers are energized by authentic, intimate relationships where they are loved and accepted for who they are, not just what they do. They thrive in environments of emotional honesty and gentle communication where they can offer and receive comfort freely.","drive":"To Comfort, Rescue, and Shield","driveDescription":"They are compelled to bring emotional comfort to those who are hurting, rescue those trapped in pain, and shield the vulnerable from further harm."},"strengths":[{"title":"Deep Empathy","description":"They possess an extraordinary ability to understand and share in the emotions of others, creating profound connections and offering genuine comfort."},{"title":"Healing Presence","description":"They have a natural gift for creating safe emotional spaces where people can process pain and begin to heal from their wounds."},{"title":"Unconditional Acceptance","description":"They excel at offering love and acceptance without judgment, helping others feel valued and worthy regardless of their circumstances."},{"title":"Protective Instincts","description":"They are naturally driven to protect others from emotional harm and to intervene when they see injustice or cruelty."}],"challenges":[{"title":"Emotional Overwhelm","description":"Their deep empathy can lead them to absorb others' pain to an unhealthy degree, resulting in emotional exhaustion and burnout."},{"title":"Difficulty with Boundaries","description":"Their desire to help everyone can make it challenging for them to set healthy limits and protect their own emotional well-being."},{"title":"Avoidance of Necessary Confrontation","description":"Their preference for harmony and emotional safety can lead them to avoid necessary but difficult conversations or decisions."}],"leadershipStyle":{"title":"Compassionate Shepherd","description":"Mercy leaders lead through care, understanding, and creating safe environments.","characteristics":["Pastoral Care","Safe Environment Creation","Patient Development","Conflict Resolution","Supportive Presence"]},"interactions":["Create emotionally safe environments where they can be vulnerable without judgment.","Appreciate their gift for understanding and comforting others in pain.","Help them maintain healthy boundaries and avoid emotional overwhelm.","Support them in learning to balance mercy with necessary accountability."],"commission":"Luke 6:36: \"Be merciful, just as your Father is merciful.\""}};
window.ARCHETYPES = [{"num":1,"name":"The Apex Visionary","slug":"apex-visionary","gifts":["catalyst","erudite","strategist"],"essence":"To architect world-changing movements built on unimpeachable truth and brilliant strategy.","section":"Section 1: The Apex Visionaries (Pure “Why” Triad)","axisSignature":"3 Why","chord":"Three visionary gifts sound at once. The Catalyst pioneers the breakthrough no one else can yet picture, the Erudite proves it will hold, and the Strategist draws the long-range map to build it. This is not a critic who names what is broken. It is an innovator who designs what comes next and has the rigor to make the old way indefensible.","atBest":"The founder the future was waiting for. They carry breakthrough vision, tested proof, and long-range design in a single hand, and use it to build institutions that outlast them. People borrow courage from the clarity of the plan.","shadow":"Under pressure the Catalyst turns critical and blames others for disappointed expectations, the Erudite retreats into the complexity of the model where it is safe and lonely, and the Strategist reorganizes people like a system diagram. The tell: they win every argument and quietly lose the room, then decide the room was the problem.","coreTension":"Every move runs a gauntlet, is it a real breakthrough, is it proven, is it the best path, so they can design a flawless plan for people whose hearts they never stopped to win.","thrive":["Founding institutions, movements, and think tanks","Pioneering a validated, long-range vision","Setting direction over managing moods","Rooms with peers who can pressure-test them"],"growthEdge":"Their next level is not a better plan, it is warmth. They mature by trading the safety of the study for the risk of connection, letting people into the unfinished middle instead of presenting only the polished conclusion.","harmonizes":"Those who lead with Service and Giving. The Servant turns the vision into built reality, and the Host funds what would otherwise stay on paper.","dissonance":"Those who lead with Mercy. The Lover's first question, is this safe for the heart, can feel like a delay, while the Visionary's finished plan can land as cold, and that very tension keeps a movement both true and humane.","scripture":"\"Where there is no vision, the people perish.\" (Proverbs 29:18)","exemplar":"The Apostle Paul: a pioneer of new territory, a rigorously trained mind, and a strategic church-planter who still had to learn that knowledge without love is nothing."},{"num":2,"name":"The Principled Reformer","slug":"principled-reformer","gifts":["catalyst","servant","erudite"],"essence":"To ground revolutionary ideas in meticulous research and diligent, hands-on work.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Catalyst pioneers a better way, the Erudite proves it is sound, and the Servant builds it by hand. Innovation here is never theoretical. It is a breakthrough carried into the world through meticulous work and defended with well-researched fact.","atBest":"A reformer whose ideas are not just loud but load-bearing. They challenge the broken system, do the homework to prove the case, then quietly build the working prototype that makes the old way impossible to defend.","shadow":"The Catalyst grows critical, the Erudite hardens pride into contempt for sloppy thinking, and the Servant slips into silent martyrdom, keeping score of all the work no one else would touch. The tell: righteous exhaustion, and resentment dressed up as principle.","coreTension":"Between the Catalyst's urge to move now and the Erudite's need to be certain first, with the Servant caught doing the labor of both.","thrive":["Reforming institutions from the inside","Building working proof-of-concepts","Research-backed advocacy","High-integrity, detail-critical work"],"growthEdge":"They mature by letting good-enough ship, and by naming what they need out loud instead of over-functioning in silence until they burn out.","harmonizes":"Those who lead with Encouragement and Giving, who can rally people to the reform and resource it while the Reformer proves and builds it.","dissonance":"Those who lead with Mercy, who may feel the Reformer's exacting standards as coldness, even when the rigor is its own form of love.","scripture":"\"Let us not become weary in doing good.\" (Galatians 6:9)","exemplar":"Nehemiah: he named the ruin, counted the stones by night, and rebuilt the wall by hand against fierce opposition."},{"num":3,"name":"The Scholarly Investor","slug":"scholarly-investor","gifts":["catalyst","erudite","host"],"essence":"To validate transformative ideas with rigorous analysis and then strategically fund their implementation.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Catalyst pioneers the disruptive idea, the Erudite validates it, and the Host asks how to fund and scale it. This chord does not just imagine the new venture. It underwrites it.","atBest":"The person who can spot a breakthrough, prove its worth, and move real resources behind it. They turn validated vision into funded reality, backing innovation with capital and rigor rather than hope.","shadow":"The Catalyst turns impatient and critical, the Erudite over-analyzes past the moment of opportunity, and the Host starts controlling how every dollar is used and judging others' stewardship. The tell: a brilliant, fully-researched plan that never ships because the terms are never quite safe enough.","coreTension":"Between the Catalyst's appetite for bold risk and the Host's instinct for prudent, protected investment.","thrive":["Venture philanthropy and impact investing","Funding validated, high-upside ideas","Due diligence that still moves","Building the resource engine behind a vision"],"growthEdge":"They grow by giving without controlling the outcome, and by trusting a proven team enough to release the resources and let go.","harmonizes":"Those who lead with Service and Encouragement, who turn the funded idea into hands-on execution and momentum.","dissonance":"Those who lead with Mercy, whose give-in-the-moment compassion can feel audited by the Investor's strategic caution.","scripture":"\"Well done, good and faithful servant... I will put you in charge of many things.\" (Matthew 25:23)","exemplar":"Joseph in Egypt: he read what was coming, engineered the strategy, and stewarded the storehouses that saved nations."},{"num":4,"name":"The Insightful Inspirer","slug":"insightful-inspirer","gifts":["catalyst","erudite","enthusiast"],"essence":"To translate complex truths into compelling, hopeful narratives that rally people to a cause.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Catalyst pioneers the breakthrough insight, the Erudite grounds it in truth, and the Enthusiast sets it on fire in a crowd. Innovation here becomes a story people can feel, not just a case they can follow.","atBest":"The one who makes a hard, true idea irresistible. They translate rigorous, revolutionary thinking into a hopeful narrative that moves a room, so the breakthrough spreads instead of sitting in a journal.","shadow":"The Catalyst gets critical, the Erudite grows proud of its rigor, and the Enthusiast, needing the room's approval, softens the hard truth until it stops meaning anything. The tell: a thrilling talk that quietly betrays the very insight it was built to carry.","coreTension":"Between the drive to tell the whole truth and the hunger to keep the room inspired and on-side.","thrive":["Keynote teaching and public communication","Turning complex truth into movement","Advocacy that both informs and inspires","Rallying people to a validated cause"],"growthEdge":"They mature by keeping the edge on the message even when a crowd would rather be flattered, and by following through long after the applause.","harmonizes":"Those who lead with Service and Leadership, who turn the inspired crowd into organized, lasting action.","dissonance":"Those who lead with Service, whose heads-down, unglamorous diligence can feel overlooked beside the Inspirer's spotlight, though it is what makes the message land.","scripture":"\"How beautiful are the feet of those who bring good news.\" (Romans 10:15)","exemplar":"Apollos: learned, eloquent, and fervent, he watered what others planted and argued the truth in public with power."},{"num":5,"name":"The Compassionate Sage","slug":"compassionate-sage","gifts":["catalyst","erudite","lover"],"essence":"To deliver challenging truths with profound wisdom and deep empathy for the human heart.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Catalyst pioneers the hard truth, the Erudite tests it, and the Lover carries it with mercy. This chord innovates on the inside of people, naming what must change without crushing the one who must change it.","atBest":"A sage who can say the unsayable and leave the hearer feeling seen rather than exposed. They fuse breakthrough insight and deep study with real compassion, so their truth heals instead of merely winning.","shadow":"The Catalyst's edge turns harsh, the Erudite retreats into analysis, and the Lover absorbs everyone's pain until there is no self left to speak from. The tell: they either wound in the name of truth or go silent in the name of kindness, and swing between the two.","coreTension":"Between the prophetic drive to confront and the merciful need to protect, often inside the same sentence.","thrive":["Wise counsel and spiritual direction","Truth-telling in tender situations","Teaching that forms character, not just minds","Mentoring people through hard growth"],"growthEdge":"They grow by setting boundaries around their own heart, so they can stay present to another's pain without drowning in it.","harmonizes":"Those who lead with Leadership and Giving, who give their wisdom a structure and a platform.","dissonance":"Those who lead with Prophecy in its rawer form, whose speed to confront can feel reckless to the Sage who weighs the cost to the heart.","scripture":"\"Speaking the truth in love, we will grow up.\" (Ephesians 4:15)","exemplar":"Samuel: he carried hard prophetic words and deep discernment, yet grieved over the people he had to correct."},{"num":6,"name":"The Visionary Implementer","slug":"visionary-implementer","gifts":["catalyst","servant","strategist"],"essence":"To translate a grand, disruptive vision into a practical, step-by-step plan executed with excellence.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Catalyst pioneers the disruptive vision, the Strategist turns it into a system, and the Servant executes it with excellence. This chord closes the gap most visionaries never do, from breakthrough idea to shipped reality.","atBest":"The rare innovator who also delivers. They dream the new thing, architect the plan, then do the hands-on work to make it real, step by disciplined step.","shadow":"The Catalyst grows impatient, the Strategist over-controls the plan, and the Servant over-functions until it resents the very mission it chose. The tell: a leader carrying too much of the load, snapping at a team it never trusted to help.","coreTension":"Between the Catalyst's revolutionary leaps and the Servant's need for a stable, finishable task, refereed by the Strategist's plan.","thrive":["Turning bold vision into shipped product","Operational leadership of change","Building and running new systems","Execution-critical launches"],"growthEdge":"They mature by delegating the work instead of hoarding it, and by trusting the team enough to let the plan flex.","harmonizes":"Those who lead with Encouragement and Mercy, who keep the people energized and cared for while the machine runs.","dissonance":"Those who lead with Teaching, whose call for more study can feel like drag to the Implementer's bias toward action.","scripture":"\"Commit to the Lord whatever you do, and he will establish your plans.\" (Proverbs 16:3)","exemplar":"Zerubbabel: he carried the vision, held the plan, and laid the temple's foundation stone by stone."},{"num":7,"name":"The Resourced Revolutionary","slug":"resourced-revolutionary","gifts":["catalyst","host","strategist"],"essence":"To architect and fund large-scale, transformative movements and institutions.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Catalyst pioneers the movement, the Host funds and provisions it, and the Strategist builds it to last. This chord does not just start revolutions. It endows them.","atBest":"The builder of enduring, well-resourced movements. They pair breakthrough vision with the capital and architecture to make it permanent, founding the institution rather than just lighting the spark.","shadow":"The Catalyst turns demanding, the Host starts controlling the purse and judging others' stewardship, and the Strategist subordinates people to the plan. The tell: an empire-builder who forgets the empire was supposed to serve someone.","coreTension":"Between the Catalyst's willingness to spend everything on the vision and the Host's instinct to protect and steward it.","thrive":["Founding funded institutions and ministries","Scaling a movement sustainably","Capital strategy behind a cause","Long-horizon institution-building"],"growthEdge":"They grow by holding power and money with an open hand, remembering that stewardship serves the mission, not the reverse.","harmonizes":"Those who lead with Service and Encouragement, who humanize the institution and keep it from becoming a machine.","dissonance":"Those who lead with Mercy, who can feel the Revolutionary optimizes the system at the cost of the single hurting person.","scripture":"\"To whom much is given, much will be required.\" (Luke 12:48)","exemplar":"King David: he cast the vision, gathered the resources, and drew the plans for a temple he would not live to build."},{"num":8,"name":"The Galvanizing Leader","slug":"galvanizing-leader","gifts":["catalyst","enthusiast","strategist"],"essence":"To fuse a bold, strategic vision with an infectious passion that mobilizes and inspires teams.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Catalyst pioneers the bold vision, the Strategist maps it, and the Enthusiast makes people run toward it. This chord fuses breakthrough and blueprint with contagious fire.","atBest":"The leader who moves crowds toward a genuinely new future. They combine disruptive vision, a real plan, and infectious passion, so people do not just admire the idea, they enlist in it.","shadow":"The Catalyst grows critical, the Strategist over-controls, and the Enthusiast overpromises to keep the energy high. The tell: soaring launches, thin follow-through, and a trail of inspired people left holding an unfinished plan.","coreTension":"Between the Strategist's disciplined roadmap and the Enthusiast's improvised, in-the-moment momentum.","thrive":["Mobilizing teams around a bold vision","Founding and scaling ventures","Turnarounds that need belief and structure","High-energy strategic leadership"],"growthEdge":"They mature by protecting the plan from their own hype, and by finishing quietly what they launched loudly.","harmonizes":"Those who lead with Service and Teaching, who supply the follow-through and the substance beneath the excitement.","dissonance":"Those who lead with Teaching, who can experience the Galvanizer as all thrust and no ballast until the claims are tested.","scripture":"\"Let us run with perseverance the race marked out for us.\" (Hebrews 12:1)","exemplar":"Joshua: he cast a bold vision of the land, held the strategy, and rallied a whole people to cross over."},{"num":9,"name":"The Protective Visionary","slug":"protective-visionary","gifts":["catalyst","strategist","lover"],"essence":"To lead with decisive, transformative vision while fiercely protecting the well-being of the people involved.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Catalyst pioneers decisive change, the Strategist gives it direction, and the Lover guards the people inside the storm. This chord innovates and leads while refusing to spend human beings as fuel.","atBest":"The leader who drives hard change and covers the vulnerable while doing it. They make the bold call and the humane one at once, so transformation does not leave casualties behind.","shadow":"The Catalyst turns harsh, the Strategist turns controlling, and the Lover, torn between mission and the wounded, either freezes or erupts. The tell: a protector who alternates between fierce advocacy and burned-out withdrawal.","coreTension":"Between the drive to push the mission forward and the vow to protect the people the mission costs.","thrive":["Leading change in human-heavy systems","Crisis leadership with a conscience","Protecting teams through hard transitions","Reform that guards the vulnerable"],"growthEdge":"They grow by setting boundaries so their care does not curdle into resentment, and by trusting others to help carry the shield.","harmonizes":"Those who lead with Giving and Service, who resource and staff the protection they promise.","dissonance":"Those who lead with Leadership in its coldest form, who can see the Protective Visionary's people-first pauses as drag on the plan.","scripture":"\"Defend the weak and the fatherless; uphold the cause of the poor.\" (Psalm 82:3)","exemplar":"Moses: he confronted Pharaoh, strategized an exodus, and kept interceding for a people who wore him out."},{"num":10,"name":"The Master Craftsman","slug":"master-craftsman","gifts":["servant","erudite","strategist"],"essence":"To design and execute complex projects with a masterful blend of strategic planning and meticulous craftsmanship.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Erudite masters the craft, the Strategist designs the build, and the Servant executes every detail. This is intelligent execution, the architect who also knows how to cut the stone.","atBest":"The one who does things right, from first principle to final polish. They pair deep expertise, a clear plan, and relentless craftsmanship, so what they make simply works and lasts.","shadow":"The Erudite falls into analysis paralysis, the Strategist over-organizes, and the Servant refuses to delegate because no one meets the standard. The tell: a bottleneck of one, redoing everyone else's work at midnight.","coreTension":"Between the Erudite's need to study more and the Servant's itch to start doing, held in check by the Strategist's plan.","thrive":["Engineering, surgery, software, fine craft","Complex builds demanding precision","Mastery-level technical leadership","Quality-critical execution"],"growthEdge":"They mature by teaching their craft rather than guarding it, multiplying through others instead of doing everything themselves.","harmonizes":"Those who lead with Encouragement and Giving, who bring warmth and resources to the workshop.","dissonance":"Those who lead with Prophecy, whose fast, intuitive leaps can feel like a threat to the Craftsman's need to get it exactly right.","scripture":"\"Do you see someone skilled in their work? They will serve before kings.\" (Proverbs 22:29)","exemplar":"Bezalel: filled with the Spirit for wisdom, understanding, and skill to build the tabernacle with exact excellence."},{"num":11,"name":"The Prudent Architect","slug":"prudent-architect","gifts":["erudite","host","strategist"],"essence":"To build enduring, well-resourced institutions based on deep research and sound strategic planning.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","chord":"The Erudite researches deeply, the Host resources wisely, and the Strategist builds for the long horizon. This chord raises institutions on a foundation of proof, provision, and plan.","atBest":"The builder of enduring, well-funded, evidence-based institutions. They study before they spend, spend before they scale, and design so the thing still stands in a generation.","shadow":"The Erudite over-studies, the Host over-controls the resources, and the Strategist over-systematizes, until the institution serves its own machinery. The tell: a perfectly governed structure that has quietly forgotten the people it was built for.","coreTension":"Between the Erudite's caution to be sure and the Strategist's push to commit, with the Host guarding the treasury.","thrive":["Founding durable institutions","Endowment and long-range planning","Research-driven strategy","Governance and stewardship at scale"],"growthEdge":"They grow by remembering that prudence is a means, not the mission, and by giving warmth and spontaneity room inside the plan.","harmonizes":"Those who lead with Encouragement and Mercy, who keep the institution human.","dissonance":"Those who lead with Prophecy, who can feel the Architect's caution as resistance to necessary disruption.","scripture":"\"Which of you, wanting to build a tower, does not first sit down and count the cost?\" (Luke 14:28)","exemplar":"Solomon in his wisdom: he gathered knowledge, marshaled resources, and built to last, before he lost the plot."},{"num":12,"name":"The Engaging Mentor","slug":"engaging-mentor","gifts":["erudite","enthusiast","strategist"],"essence":"To develop people by combining clear, strategic guidance with inspiring, motivational coaching.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Erudite brings depth, the Enthusiast brings warmth, and the Strategist brings direction. This chord develops people, pairing clear guidance with genuine inspiration and a plan for growth.","atBest":"The mentor who makes growth both clear and exciting. They know the material, believe in the person, and hold a path for them, so people leave not just informed but changed and aimed.","shadow":"The Erudite lectures, the Enthusiast needs to be liked, and the Strategist manages people as a pipeline. The tell: mentoring that becomes performance, long on charisma and plans, short on the patient, unglamorous work of one real life.","coreTension":"Between the urge to direct and the instinct to affirm and connect.","thrive":["Teaching, coaching, and leadership development","Building people and programs","Curriculum and mentoring systems","Inspiring disciplined growth"],"growthEdge":"They mature by staying with the slow, individual work of formation instead of scaling themselves into a brand.","harmonizes":"Those who lead with Service and Mercy, who ground the mentoring in care and follow-through.","dissonance":"Those who lead with Prophecy, who can find the Mentor's developmental patience too slow for the moment.","scripture":"\"The things you have heard from me... entrust to reliable people who will also teach others.\" (2 Timothy 2:2)","exemplar":"Priscilla, who with Aquila took Apollos aside and explained the way of God to him more adequately."},{"num":13,"name":"The Wise Shepherd","slug":"wise-shepherd","gifts":["erudite","strategist","lover"],"essence":"To lead with profound wisdom and a clear plan, while providing deep, pastoral care for the team.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","chord":"The Erudite brings wisdom, the Strategist brings a clear path, and the Lover brings pastoral warmth. This chord leads people somewhere worth going and cares for them the whole way.","atBest":"The leader people trust with their souls. They combine sound judgment, a real plan, and deep compassion, so guidance feels safe rather than driven, and direction comes wrapped in care.","shadow":"The Erudite withdraws into analysis, the Strategist quietly controls, and the Lover absorbs the team's pain until it cannot lead. The tell: a shepherd so attuned to everyone's feelings that no decision gets made, or one who intellectualizes care until it stops being felt.","coreTension":"Between the clarity to lead decisively and the tenderness to move at the pace of the wounded.","thrive":["Pastoral and organizational leadership","Counseling-informed management","Guiding teams through change with care","People-first strategy"],"growthEdge":"They grow by making the hard call even when it disappoints, trusting that clear direction is itself a form of care.","harmonizes":"Those who lead with Service and Giving, who turn wise, caring direction into tangible provision.","dissonance":"Those who lead with Prophecy, whose urgency to confront can feel like a threat to the safety the Shepherd is building.","scripture":"\"David shepherded them with integrity of heart; with skillful hands he led them.\" (Psalm 78:72)","exemplar":"David the shepherd-king: skillful leadership and a shepherd's heart in one person."},{"num":14,"name":"The Practical Revolutionary","slug":"practical-revolutionary","gifts":["catalyst","servant","host"],"essence":"To fuel radical change not with words, but with tireless work and the generous provision of practical resources.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","chord":"The Catalyst pioneers radical change, the Servant builds it by hand, and the Host funds it. This chord does not just preach a new world. It shows up with tools and a checkbook and starts making one.","atBest":"The revolutionary you can actually follow. They turn a bold new vision into tangible work and real provision, proving the future by building a piece of it you can stand in.","shadow":"The Catalyst turns critical, the Servant over-functions into martyrdom, and the Host controls how the resources get used. The tell: a tireless builder doing everything, resenting the very people they refuse to let help.","coreTension":"Between the Catalyst's hunger to overturn and the Servant-Host instinct to steward what already works.","thrive":["Grassroots movements and social enterprise","Hands-on, funded innovation","Building tangible alternatives","Turning protest into provision"],"growthEdge":"They mature by receiving help instead of proving themselves through overwork, and by giving without strings.","harmonizes":"Those who lead with Encouragement and Teaching, who give the movement a voice and a rigorous case.","dissonance":"Those who lead with Leadership, whose slower, system-first pace can frustrate the Revolutionary's build-it-now drive.","scripture":"\"Let us not love with words or speech but with actions and in truth.\" (1 John 3:18)","exemplar":"The first believers in Acts, who reimagined community and backed the vision by selling what they had so no one among them was in need."},{"num":15,"name":"The Faithful Steward","slug":"faithful-steward","gifts":["servant","erudite","host"],"essence":"To manage and multiply resources with profound diligence, wisdom, and meticulous attention to detail.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","chord":"The Servant works diligently, the Erudite brings precision, and the Host multiplies resources. This chord manages what it is given with rare care, and makes it grow.","atBest":"The most trustworthy hands in the room. They combine hard work, exact knowledge, and wise generosity, so resources are not just protected but multiplied and deployed for good.","shadow":"The Servant over-functions, the Erudite nitpicks, and the Host controls and audits. The tell: a steward so careful that giving becomes gatekeeping, and diligence becomes control.","coreTension":"Between the drive to work and give freely and the need to account for every detail.","thrive":["Operations, finance, administration","Resource and program management","Meticulous stewardship of assets","Building reliable systems of provision"],"growthEdge":"They grow by giving with open hands and trusting people with what they steward, loosening the grip that protection can become.","harmonizes":"Those who lead with Encouragement and Prophecy, who bring vision and life to what the Steward faithfully keeps.","dissonance":"Those who lead with Prophecy, whose disruptive risk can feel careless to the Steward's careful eye.","scripture":"\"Well done, good and faithful servant! You have been faithful with a few things.\" (Matthew 25:21)","exemplar":"Eliezer of Damascus, Abraham's trusted steward, entrusted with his master's whole house and his son's future."},{"num":16,"name":"The Joyful Benefactor","slug":"joyful-benefactor","gifts":["servant","enthusiast","host"],"essence":"To create a culture of celebration and community through tireless service and lavish hospitality.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"2 How · 1 Who","chord":"The Servant works, the Enthusiast celebrates, and the Host provides. This chord throws open the doors, does the labor of hospitality, and makes belonging feel like a party.","atBest":"The one who makes community feel like home. They pair tireless service, contagious joy, and open-handed generosity, so people feel fed, welcomed, and glad they came.","shadow":"The Servant over-gives, the Enthusiast needs the room's delight, and the Host manages the guest list and the budget. The tell: a host so busy producing the experience that they never enjoy it, quietly keeping score of who noticed.","coreTension":"Between the joy of giving freely and the exhaustion of always being the one who makes it happen.","thrive":["Hospitality, events, community-building","Fundraising and celebration","Creating welcoming cultures","Care ministries and gatherings"],"growthEdge":"They grow by letting themselves be served, and by giving from fullness rather than to earn belonging.","harmonizes":"Those who lead with Teaching and Leadership, who add depth and direction to the warmth.","dissonance":"Those who lead with Prophecy, whose confronting edge can feel like it spoils the harmony the Benefactor works to create.","scripture":"\"Offer hospitality to one another without grumbling.\" (1 Peter 4:9)","exemplar":"Lydia, the dealer in purple, who opened her home and resources to the young church the moment her heart was opened."},{"num":17,"name":"The Master Provider","slug":"master-provider","gifts":["servant","host","strategist"],"essence":"To build and manage the operational systems that provide for a community's long-term practical needs.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","chord":"The Servant executes, the Host resources, and the Strategist plans. This chord builds the systems that quietly keep a whole community fed, funded, and functioning.","atBest":"The backbone no one sees and everyone depends on. They combine diligent work, wise provision, and long-range planning to build the operational engine that makes everyone else's mission possible.","shadow":"The Servant over-functions, the Host controls the resources, and the Strategist over-systematizes. The tell: an indispensable operator who cannot rest and will not delegate, running on quiet resentment.","coreTension":"Between the impulse to just handle it now and the discipline to build a system that outlasts them.","thrive":["Operations and logistics leadership","Building provision systems at scale","Administration and resource planning","Making organizations actually run"],"growthEdge":"They grow by building others up to share the load, so the system does not depend on their exhaustion.","harmonizes":"Those who lead with Encouragement and Mercy, who keep the operation human and the team seen.","dissonance":"Those who lead with Prophecy, whose appetite for disruption can threaten the stable systems the Provider protects.","scripture":"\"She gets up while it is still night; she provides food for her family.\" (Proverbs 31:15)","exemplar":"Obadiah, the palace steward who quietly fed and hid a hundred prophets through a famine."},{"num":18,"name":"The Tender Provider","slug":"tender-provider","gifts":["servant","host","lover"],"essence":"To express deep compassion by tirelessly working and generously giving to meet the tangible needs of the hurting.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"2 How · 1 Who","chord":"The Servant acts, the Host provides, and the Lover feels. This chord meets suffering with practical, generous, tangible care, love you can hold in your hands.","atBest":"Compassion that shows up with groceries. They pair hard work, real resources, and deep empathy, so hurting people are not just comforted but actually cared for, in body and in heart.","shadow":"The Servant over-gives, the Host tries to control the help, and the Lover over-identifies until it burns out. The tell: a caregiver pouring out until empty, unable to receive, quietly drowning in others' needs.","coreTension":"Between the boundless desire to help and the finite body doing the helping.","thrive":["Caregiving, chaplaincy, relief work","Practical mercy ministries","Meeting tangible needs of the hurting","Hospitality to the suffering"],"growthEdge":"They grow by accepting their own limits, learning that a well-placed no is what keeps their yes alive.","harmonizes":"Those who lead with Teaching and Leadership, who help the care scale without losing its heart.","dissonance":"Those who lead with Prophecy, whose hard truths can feel harsh to the Tender Provider's protective warmth.","scripture":"\"She opens her arms to the poor and extends her hands to the needy.\" (Proverbs 31:20)","exemplar":"Dorcas (Tabitha), always doing good and helping the poor, who sewed garments for the widows with her own hands."},{"num":19,"name":"The Compassionate Agitator","slug":"compassionate-agitator","gifts":["catalyst","enthusiast","lover"],"essence":"To challenge injustice and speak hard truths, fueled by a deep love for people and a desire to rally them to a better way.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","chord":"The Catalyst pioneers change, the Enthusiast rallies people, and the Lover feels their pain. This chord innovates for justice, driven by love for the very people the broken system is hurting.","atBest":"The activist with a tender heart. They call out what is wrong and light people up to change it, all fueled by genuine compassion rather than mere anger, so their disruption heals rather than just burns.","shadow":"The Catalyst turns bitter, the Enthusiast rides the crowd's outrage, and the Lover is swamped by the suffering it sees. The tell: passion that curdles into cynicism, or an agitator so wounded by the cause that it cannot stop fighting long enough to heal.","coreTension":"Between the fire to confront injustice and the tenderness that makes the injustice unbearable to witness.","thrive":["Advocacy and justice movements","Community organizing with heart","Reform driven by compassion","Giving voice to the overlooked"],"growthEdge":"They grow by tending their own wounds so their fight comes from love, not lingering pain, and by pacing themselves so the fire lasts.","harmonizes":"Those who lead with Teaching and Leadership, who give the movement rigor and a workable plan.","dissonance":"Those who lead with Giving at its most cautious, whose measured pace can feel like complicity to the Agitator.","scripture":"\"Learn to do right; seek justice. Defend the oppressed.\" (Isaiah 1:17)","exemplar":"Amos, the shepherd-prophet who cried for justice to roll on like a river, out of love for a people being crushed."},{"num":20,"name":"The Devoted Caretaker","slug":"devoted-caretaker","gifts":["servant","enthusiast","lover"],"essence":"To offer holistic care for others through uplifting encouragement, empathetic presence, and tangible acts of service.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 How · 2 Who","chord":"The Servant does, the Enthusiast encourages, and the Lover feels. This chord surrounds people with holistic care, practical help, uplifting words, and a warm, safe presence.","atBest":"The person who makes others feel completely held. They combine tangible help, genuine encouragement, and deep empathy, meeting body and heart at once.","shadow":"The Servant over-functions, the Enthusiast needs to be needed, and the Lover loses itself in others. The tell: a caretaker with no self left, whose giving has quietly become the only way it knows how to be loved.","coreTension":"Between caring for everyone else and having a self that also needs care.","thrive":["Caregiving and nurturing roles","Hospitality and pastoral care","Encouraging and serving the hurting","Building warm, safe communities"],"growthEdge":"They grow by receiving care as freely as they give it, and by believing they are loved for who they are, not what they do.","harmonizes":"Those who lead with Teaching and Leadership, who add wisdom and direction to the warmth.","dissonance":"Those who lead with Prophecy, whose bluntness can feel like a wound to the Caretaker's gentleness.","scripture":"\"Carry each other's burdens, and in this way you will fulfill the law of Christ.\" (Galatians 6:2)","exemplar":"Martha of Bethany, at her best: hands full of service and a home thrown open to care for the ones she loved."},{"num":21,"name":"The Affectionate Counselor","slug":"affectionate-counselor","gifts":["erudite","enthusiast","lover"],"essence":"To create a safe and uplifting space where deep empathy is paired with wise, insightful counsel.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","chord":"The Erudite brings insight, the Enthusiast brings warmth, and the Lover brings empathy. This chord creates a safe, uplifting space where wise counsel meets a listening heart.","atBest":"The counselor you can tell anything. They pair real understanding, genuine encouragement, and deep compassion, so people feel both truly seen and gently guided.","shadow":"The Erudite over-analyzes the person, the Enthusiast needs to be liked, and the Lover absorbs the pain. The tell: a counselor who over-identifies with everyone, gives advice to be loved, and goes home carrying wounds that were never theirs.","coreTension":"Between the clarity to name what is true and the warmth that never wants to hurt.","thrive":["Counseling and spiritual direction","Teaching that heals","Small-group and one-on-one care","Safe spaces for hard conversations"],"growthEdge":"They grow by holding boundaries in the counseling seat, offering presence without taking on what is not theirs to carry.","harmonizes":"Those who lead with Leadership and Service, who help turn insight into concrete next steps.","dissonance":"Those who lead with Prophecy, whose confrontational edge can feel unsafe in the tender space the Counselor builds.","scripture":"\"A word fitly spoken is like apples of gold in settings of silver.\" (Proverbs 25:11)","exemplar":"Barnabas, the son of encouragement, whose warm, wise belief in people drew out the best in them."},{"num":22,"name":"The Lavish Celebrant","slug":"lavish-celebrant","gifts":["enthusiast","host","lover"],"essence":"To build community by generously creating beautiful, welcoming experiences where people feel cherished and connected.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 How · 2 Who","chord":"The Enthusiast celebrates, the Host provides, and the Lover cherishes. This chord builds community through beauty and belonging, gatherings where everyone feels seen, fed, and treasured.","atBest":"The one who makes belonging tangible. They combine contagious joy, open-handed provision, and deep warmth to create experiences where people feel genuinely cherished.","shadow":"The Enthusiast needs the room's delight, the Host manages the production, and the Lover fears anyone feeling left out. The tell: a host performing warmth, anxious behind the glow, needing the party to prove they matter.","coreTension":"Between creating joy for others and finding it for themselves.","thrive":["Hospitality, events, community life","Celebration and belonging-building","Care through shared experience","Making people feel cherished"],"growthEdge":"They grow by resting in their own worth apart from the applause, so hospitality flows from fullness, not fear.","harmonizes":"Those who lead with Teaching and Leadership, who anchor the celebration with substance and structure.","dissonance":"Those who lead with Prophecy, whose truth-telling can feel like it breaks the warmth the Celebrant is protecting.","scripture":"\"When you give a banquet, invite the poor... and you will be blessed.\" (Luke 14:13-14)","exemplar":"The father in the parable, who threw the feast, killed the fatted calf, and celebrated the son who came home."},{"num":23,"name":"The Encouraging Shepherd","slug":"encouraging-shepherd","gifts":["enthusiast","strategist","lover"],"essence":"To lead teams toward a goal by fostering a culture of profound psychological safety, connection, and inspiration.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","chord":"The Enthusiast inspires, the Strategist leads, and the Lover cares. This chord builds teams on psychological safety, guiding toward a goal while making everyone feel they belong.","atBest":"The leader people would follow anywhere. They pair motivating vision, clear direction, and genuine care, creating cultures where people feel safe enough to do their best work.","shadow":"The Enthusiast avoids hard truths, the Strategist quietly steers, and the Lover cannot bear anyone's disappointment. The tell: a leader so committed to everyone feeling good that accountability disappears and the goal drifts.","coreTension":"Between keeping the team happy and holding them to the standard the goal requires.","thrive":["People-first team leadership","Culture and morale building","Coaching toward shared goals","Leading with empathy and vision"],"growthEdge":"They grow by having the hard conversation, learning that real care sometimes sounds like a clear expectation.","harmonizes":"Those who lead with Service and Teaching, who supply the execution and substance behind the vision.","dissonance":"Those who lead with Prophecy, whose directness can feel like a threat to the safety the Shepherd is building.","scripture":"\"Encourage one another and build each other up.\" (1 Thessalonians 5:11)","exemplar":"Timothy, the young pastor urged to lead his people with gentleness, conviction, and genuine care."},{"num":24,"name":"The Practical Pioneer","slug":"practical-pioneer","gifts":["catalyst","servant","enthusiast"],"essence":"To inspire people to join a transformative cause through joyful, hands-on work and infectious optimism.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Catalyst pioneers the new way, the Servant builds it, and the Enthusiast makes it contagious. This chord launches fresh ventures with rolled-up sleeves and infectious optimism.","atBest":"The founder people love to build with. They combine breakthrough ideas, hands-on work, and joyful energy, so a new venture feels less like a risk and more like an adventure worth joining.","shadow":"The Catalyst turns critical, the Servant over-functions, and the Enthusiast overpromises. The tell: a fast start and a messy middle, a pioneer who launches three things, finishes none, and burns out the friends who followed.","coreTension":"Between the excitement of starting and the grind of finishing.","thrive":["Startups and new initiatives","Hands-on innovation with a team","Pioneering programs and ventures","Turning fresh ideas into first steps"],"growthEdge":"They grow by finishing what they start, and by protecting their team from the cost of their own restlessness.","harmonizes":"Those who lead with Teaching and Leadership, who bring rigor and a plan to the momentum.","dissonance":"Those who lead with Teaching, whose need to slow down and get it right can feel like a brake on the Pioneer's build-now energy.","scripture":"\"See, I am doing a new thing! Now it springs up; do you not perceive it?\" (Isaiah 43:19)","exemplar":"Peter, the impulsive pioneer who stepped out of the boat and later opened the door of the church to the nations."},{"num":25,"name":"The Compassionate Builder","slug":"compassionate-builder","gifts":["catalyst","servant","lover"],"essence":"To see what is broken, feel the pain it causes, and be compelled to physically build a tangible solution.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Catalyst sees what is broken, the Lover feels the pain it causes, and the Servant is compelled to build the fix. This chord innovates out of compassion, then hammers the solution together by hand.","atBest":"The one who does not just grieve a problem, they build the answer. They pair a pioneering eye, deep empathy, and tireless hands, so love becomes a shelter, a tool, a thing that actually holds.","shadow":"The Catalyst turns critical, the Lover drowns in the suffering, and the Servant over-functions to numb the ache. The tell: a builder working themselves to exhaustion to outrun a pain they will not stop to feel.","coreTension":"Between the compassion that takes the problem personally and the hands that can only build so fast.","thrive":["Building solutions for the hurting","Hands-on mercy and relief work","Designing tools and spaces that heal","Turning empathy into infrastructure"],"growthEdge":"They grow by letting themselves feel the grief instead of working around it, and by accepting help before the tank hits empty.","harmonizes":"Those who lead with Teaching and Leadership, who help their compassion scale and last.","dissonance":"Those who lead with Leadership at its most detached, whose focus on the metric can feel heartless to the Builder.","scripture":"\"Whatever you did for one of the least of these... you did for me.\" (Matthew 25:40)","exemplar":"Noah, who heard the warning, felt its weight, and spent a hundred years building the ark that carried life through."},{"num":26,"name":"The Generous Pioneer","slug":"generous-pioneer","gifts":["catalyst","enthusiast","host"],"essence":"To fund and celebrate revolutionary new ventures, inspiring others to invest in a bold vision of the future.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Catalyst pioneers the bold venture, the Enthusiast rallies believers, and the Host funds it. This chord backs new ideas with contagious energy and open resources, inviting others to invest in a future worth building.","atBest":"The founder who makes generosity exciting. They combine breakthrough vision, infectious optimism, and open-handed provision, so people catch the dream and put their own resources behind it too.","shadow":"The Catalyst turns restless, the Enthusiast overpromises, and the Host tries to control the returns. The tell: bold, well-funded launches with thin follow-through, and generosity that quietly expects to be repaid in loyalty.","coreTension":"Between the appetite to keep launching new things and the discipline to steward what has already been started.","thrive":["Funding and championing new ventures","Fundraising and vision-casting","Launching generous initiatives","Inspiring others to invest and give"],"growthEdge":"They grow by finishing and stewarding what they start, and by giving with no strings and no scoreboard.","harmonizes":"Those who lead with Service and Teaching, who supply the follow-through and the rigor.","dissonance":"Those who lead with Teaching, whose caution can feel like cold water on the Pioneer's fire.","scripture":"\"God loves a cheerful giver.\" (2 Corinthians 9:7)","exemplar":"The Macedonian churches, who in overflowing joy gave beyond their means to fund a mission bigger than themselves."},{"num":27,"name":"The Resourced Healer","slug":"resourced-healer","gifts":["catalyst","host","lover"],"essence":"To identify the root cause of suffering and then build and fund the institutions necessary for its healing.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Catalyst finds the root of the suffering, the Host funds the remedy, and the Lover tends the wounded. This chord does not just bandage pain, it pioneers and finances the places that heal it.","atBest":"The one who turns compassion into a hospital. They pair a diagnostic eye, real resources, and deep empathy, building and funding the places where broken people get whole.","shadow":"The Catalyst grows frustrated, the Host controls the giving, and the Lover burns out on the pain. The tell: a healer who funds everyone's recovery but their own, controlling the help so tightly it stops feeling like grace.","coreTension":"Between the drive to fix the whole system of suffering and the tenderness that breaks over each person in it.","thrive":["Founding and funding healing institutions","Trauma-informed philanthropy","Building recovery and care systems","Root-cause mercy work"],"growthEdge":"They grow by receiving care themselves, and by giving without needing to manage exactly how the healing happens.","harmonizes":"Those who lead with Service and Teaching, who staff and ground the healing work.","dissonance":"Those who lead with Leadership at its most results-driven, whose efficiency can feel cold to the Healer's heart.","scripture":"\"He heals the brokenhearted and binds up their wounds.\" (Psalm 147:3)","exemplar":"The Good Samaritan, who saw the wounded stranger, tended him, and paid the innkeeper to continue the care."},{"num":28,"name":"The Meticulous Motivator","slug":"meticulous-motivator","gifts":["servant","erudite","enthusiast"],"essence":"To make work and learning enjoyable and effective through clear instruction, practical help, and positive reinforcement.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Servant works, the Erudite masters the detail, and the Enthusiast keeps it enjoyable. This chord makes excellence feel good, teaching and doing hard things with clarity, care, and encouragement.","atBest":"The one who makes mastery approachable. They combine diligent work, precise knowledge, and warm encouragement, so people learn hard things without feeling small.","shadow":"The Servant over-functions, the Erudite fusses over detail, and the Enthusiast needs approval. The tell: a helper who perfects and cheerleads until they are exhausted, unable to say the harder true thing for fear of dimming the mood.","coreTension":"Between the precision that wants it exactly right and the warmth that wants everyone to feel good about it.","thrive":["Training, teaching, and coaching","Detailed, people-friendly instruction","Onboarding and skill-building","Quality work with a human touch"],"growthEdge":"They grow by giving honest feedback even when it disappoints, and by resting before the well runs dry.","harmonizes":"Those who lead with Leadership and Prophecy, who supply direction and the courage to name hard things.","dissonance":"Those who lead with Prophecy, whose bluntness can feel jarring next to the Motivator's gentle precision.","scripture":"\"Let us consider how we may spur one another on toward love and good deeds.\" (Hebrews 10:24)","exemplar":"Ezra, who devoted himself to study the Law, to do it, and to teach it, making a hard text livable for a people."},{"num":29,"name":"The Wise Caretaker","slug":"wise-caretaker","gifts":["servant","erudite","lover"],"essence":"To provide care that is not only compassionate and practical but also deeply wise and discerning.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Servant helps, the Erudite understands, and the Lover feels. This chord offers care that is not only warm and practical but genuinely wise, help that actually fits the need.","atBest":"The caregiver who truly gets it. They pair tangible help, real discernment, and deep compassion, so their care is precise, not just kind, meeting the actual need rather than the obvious one.","shadow":"The Servant over-gives, the Erudite over-analyzes the suffering, and the Lover absorbs it. The tell: a caretaker who studies and serves everyone's pain until their own quietly goes unnoticed and unspoken.","coreTension":"Between the head that understands the problem and the heart that just wants to sit with the person.","thrive":["Caregiving with discernment","Counseling-informed service","Meeting needs wisely and warmly","Quiet, competent compassion"],"growthEdge":"They grow by voicing their own needs and limits, trusting that they too are worth caring for.","harmonizes":"Those who lead with Encouragement and Leadership, who bring energy and direction to steady care.","dissonance":"Those who lead with Prophecy, whose speed and edge can feel careless to the Caretaker's gentle thoroughness.","scripture":"\"Be devoted to one another in love. Honor one another above yourselves.\" (Romans 12:10)","exemplar":"Luke, the beloved physician, whose careful eye and caring heart tended both bodies and the story of the church."},{"num":30,"name":"The Prudent Mentor","slug":"prudent-mentor","gifts":["erudite","enthusiast","host"],"essence":"To wisely invest in the potential of others, providing both the resources and the inspiration needed for them to flourish.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Erudite brings wisdom, the Enthusiast brings belief in people, and the Host brings resources. This chord invests in potential, giving people both the insight and the means to flourish.","atBest":"The mentor who backs their belief with real support. They combine sound judgment, genuine encouragement, and open resources, so the people they invest in actually have what they need to grow.","shadow":"The Erudite lectures, the Enthusiast needs to be admired, and the Host controls the investment. The tell: a patron whose generosity carries quiet expectations, mentoring people into their own image rather than their own calling.","coreTension":"Between believing in someone's potential and controlling how they are allowed to reach it.","thrive":["Mentoring and sponsorship","Scholarship and development funding","Investing wisely in people","Coaching backed by resources"],"growthEdge":"They grow by releasing the people they invest in to their own path, giving without owning the outcome.","harmonizes":"Those who lead with Service and Leadership, who turn the investment into disciplined growth.","dissonance":"Those who lead with Prophecy, whose disruptive independence can feel ungrateful to the Mentor who invested.","scripture":"\"Each of you should use whatever gift you have received to serve others.\" (1 Peter 4:10)","exemplar":"Mordecai, who mentored Esther with wisdom and resources, then released her to a courage that was hers alone."},{"num":31,"name":"The Benevolent Counselor","slug":"benevolent-counselor","gifts":["erudite","host","lover"],"essence":"To offer wise counsel and healing, backed by the generous provision of resources to aid in restoration.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Erudite brings wisdom, the Host brings resources, and the Lover brings compassion. This chord offers counsel that comes with real help, insight and provision to aid the healing.","atBest":"The wise, generous confidant. They pair sound judgment, open resources, and deep empathy, so their counsel is not just words but a hand up, wisdom backed by tangible support.","shadow":"The Erudite over-analyzes, the Host controls the help, and the Lover over-identifies. The tell: a counselor whose generosity subtly obligates, whose care keeps others dependent rather than freeing them.","coreTension":"Between offering wisdom freely and controlling how the help gets used.","thrive":["Counsel paired with practical aid","Restorative and benevolence ministry","Wise, resourced care","Helping people rebuild"],"growthEdge":"They grow by giving counsel and help without strings, trusting people to carry their own next step.","harmonizes":"Those who lead with Leadership and Encouragement, who add direction and momentum to the care.","dissonance":"Those who lead with Prophecy, whose bluntness can feel unsafe in the gentle space the Counselor builds.","scripture":"\"Blessed are those who have regard for the weak.\" (Psalm 41:1)","exemplar":"Boaz, who counseled Ruth wisely, provided for her generously, and covered her with kindness and honor."},{"num":32,"name":"The Inspirational Implementer","slug":"inspirational-implementer","gifts":["servant","enthusiast","strategist"],"essence":"To lead teams to execute a plan with excellence by fostering a positive, high-morale, and collaborative environment.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Servant executes, the Enthusiast energizes, and the Strategist leads. This chord gets the plan done with excellence and high morale, making execution feel like a shared win.","atBest":"The leader who makes people love to deliver. They pair diligent execution, contagious positivity, and clear direction, so teams hit the goal and enjoy the climb.","shadow":"The Servant over-functions, the Enthusiast avoids conflict, and the Strategist quietly controls. The tell: a relentlessly upbeat leader who buries problems under positivity and carries the whole load to keep the mood intact.","coreTension":"Between keeping morale high and confronting what is actually going wrong.","thrive":["Team and project leadership","Execution with high morale","Turning plans into results","Building positive, productive cultures"],"growthEdge":"They grow by naming problems directly instead of out-cheering them, and by sharing the load they instinctively shoulder alone.","harmonizes":"Those who lead with Teaching and Prophecy, who bring depth and the nerve to name hard truths.","dissonance":"Those who lead with Prophecy, whose confrontation can feel like it threatens the harmony the Implementer needs.","scripture":"\"Whatever you do, work at it with all your heart, as working for the Lord.\" (Colossians 3:23)","exemplar":"Titus, sent to set things in order and encourage the churches, getting hard things done while lifting people up."},{"num":33,"name":"The Protective Architect","slug":"protective-architect","gifts":["servant","strategist","lover"],"essence":"To build great things while ensuring the process is practical, excellent, and deeply humane.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Servant executes, the Strategist designs, and the Lover guards the people. This chord builds great things while making sure the building of them stays humane.","atBest":"The builder who refuses to sacrifice people to the project. They combine diligent work, clear architecture, and genuine care, so what they build is excellent and the process is kind.","shadow":"The Servant over-functions, the Strategist over-controls, and the Lover cannot bear to disappoint. The tell: a leader torn between the plan and the people, over-working to protect both and slowly resenting each.","coreTension":"Between building it right and protecting everyone who helps build it.","thrive":["Humane operational leadership","People-safe project management","Building with care for the team","Ethical, sustainable execution"],"growthEdge":"They grow by trusting the team with hard truths and real ownership, so protection does not become control.","harmonizes":"Those who lead with Encouragement and Teaching, who bring energy and depth to steady, caring execution.","dissonance":"Those who lead with Prophecy, whose disruption can feel like a threat to the stability the Architect protects.","scripture":"\"Unless the Lord builds the house, the builders labor in vain.\" (Psalm 127:1)","exemplar":"Deborah, who led Israel with clear command and a mother's heart, refusing to march without her people."},{"num":34,"name":"The Kingdom Cultivator","slug":"kingdom-cultivator","gifts":["enthusiast","host","strategist"],"essence":"To build and grow organizations by aligning a compelling vision, strategic resources, and an inspired culture.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Enthusiast inspires, the Host resources, and the Strategist builds. This chord grows organizations by aligning a compelling vision, real provision, and an inspired culture.","atBest":"The one who grows healthy institutions. They combine motivating vision, wise resources, and clear architecture, so organizations do not just launch, they flourish and endure.","shadow":"The Enthusiast overpromises, the Host controls the resources, and the Strategist over-systematizes. The tell: a leader building an impressive organization that slowly runs on control and optics instead of the life it started with.","coreTension":"Between cultivating an inspired culture and controlling the systems that culture depends on.","thrive":["Organizational and church growth","Building healthy institutions","Culture, vision, and resource alignment","Scaling with soul"],"growthEdge":"They grow by trusting people and process over control, letting the culture breathe instead of managing it.","harmonizes":"Those who lead with Service and Teaching, who ground the vision in execution and depth.","dissonance":"Those who lead with Prophecy, whose disruptive truth can feel like a threat to the growing thing the Cultivator is protecting.","scripture":"\"I planted the seed, Apollos watered it, but God has been making it grow.\" (1 Corinthians 3:6)","exemplar":"The church at Antioch, which grew a vibrant, generous, sending culture that launched the mission to the world."},{"num":35,"name":"The Benevolent Leader","slug":"benevolent-leader","gifts":["host","strategist","lover"],"essence":"To lead with a clear vision for success, generously providing for and protecting the people on the journey.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","chord":"The Host provides, the Strategist leads, and the Lover cares. This chord leads with a clear vision for success while generously providing for and protecting the people on the journey.","atBest":"The leader you would trust with your future. They combine wise provision, clear direction, and genuine care, so people are led somewhere good and looked after all the way there.","shadow":"The Host controls the resources, the Strategist over-manages, and the Lover cannot disappoint anyone. The tell: a benevolent ruler who gives and guides so completely that people never grow up, kept comfortable and quietly dependent.","coreTension":"Between leading people toward the goal and protecting them from every hardship along the way.","thrive":["Servant-hearted executive leadership","Resourced, people-first direction","Leading organizations with care","Provision and vision together"],"growthEdge":"They grow by letting people face necessary struggle, trusting that challenge, not just comfort, is how they mature.","harmonizes":"Those who lead with Prophecy and Encouragement, who bring the challenge and energy that keep provision from becoming a cage.","dissonance":"Those who lead with Prophecy, whose confrontational edge can feel like it endangers the security the Leader provides.","scripture":"\"The greatest among you will be your servant.\" (Matthew 23:11)","exemplar":"Job in his greatness, who was eyes to the blind and feet to the lame, a father to the needy who led his house with justice."}];
window.QUESTIONS = {"likert":[{"id":1,"text":"I naturally think in terms of long-range goals and strategic plans.","gift":"strategist"},{"id":2,"text":"I am energized by challenging the status quo to bring about necessary change.","gift":"catalyst"},{"id":3,"text":"I feel most satisfied when I have completed a practical task with excellence.","gift":"servant"},{"id":4,"text":"Building many positive, encouraging relationships is one of my highest priorities.","gift":"enthusiast"},{"id":5,"text":"My primary drive is to create an environment where people feel emotionally safe and accepted.","gift":"lover"},{"id":6,"text":"I feel a deep need for quiet time alone to think, process, and recharge.","gift":"erudite"},{"id":7,"text":"I am a good manager of resources (time, money, people) and use them wisely.","gift":"host"},{"id":8,"text":"I am driven to build systems and structures that create order and ensure long-term success, and will see my plans come to fruition, even if it takes days, months, or years.","gift":"strategist"},{"id":9,"text":"When I see a problem, my first instinct is to identify the root truth, even if it's uncomfortable.","gift":"catalyst"},{"id":10,"text":"People describe me as meticulous and conscientious in the tasks I complete for them.","gift":"servant"},{"id":11,"text":"I often verbally affirm others' potential and strengths in all spheres of my life.","gift":"enthusiast"},{"id":12,"text":"I have a deep, intuitive sense of the emotional state of others and feel moved to undo their aloneness in places of pain.","gift":"lover"},{"id":13,"text":"Before I accept something as fact, I feel compelled to research and validate it for myself.","gift":"erudite"},{"id":14,"text":"I get great joy, and am gifted at being hospitable and making people feel comfortable and cherished.","gift":"host"},{"id":15,"text":"I am a natural leader and take a long-term view of leadership and the development of others.","gift":"strategist"},{"id":16,"text":"I am more concerned with integrity and authenticity than with keeping everyone comfortable.","gift":"catalyst"},{"id":17,"text":"It frustrates me when I see people not doing their fair share of the work.","gift":"servant"},{"id":18,"text":"I am energized by rallying people together around a hopeful, positive vision.","gift":"enthusiast"},{"id":19,"text":"I am known for my long-suffering unconditional love and acceptance.","gift":"lover"},{"id":20,"text":"I research deeper and more complex topics than most others just for the sake of knowing the information.","gift":"erudite"},{"id":21,"text":"I usually have what others need, such as snacks, drinks, or other useful items, such as tissues, before others know that they need it.","gift":"host"},{"id":22,"text":"I have goals in place and don't like to deviate from them until they are completed.","gift":"strategist"},{"id":23,"text":"I am a pioneering spirit, always having new and innovative ideas and solutions.","gift":"catalyst"},{"id":24,"text":"People can count on me to be dependable and to finish the tasks I start.","gift":"servant"},{"id":25,"text":"I feel fulfilled when I can inspire and rally others to become passionate about what I am most passionate about at a given time.","gift":"enthusiast"},{"id":26,"text":"I tend to deescalate conflict and am often a peacemaker.","gift":"lover"},{"id":27,"text":"I am frustrated by superficial conversations that don't interest me and prefer deep, intellectually stimulating discussions.","gift":"erudite"},{"id":28,"text":"I am super resourceful.","gift":"host"},{"id":29,"text":"I have little patience for activities that do not align with the main goal or vision.","gift":"strategist"},{"id":30,"text":"I feel compelled to speak up against injustice or hypocrisy.","gift":"catalyst"},{"id":31,"text":"I show my love for others by taking practical action to meet their tangible needs.","gift":"servant"},{"id":32,"text":"I am naturally optimistic and believe the best about people and situations.","gift":"enthusiast"},{"id":33,"text":"I can become emotionally overwhelmed because I sometimes absorb the pain of others.","gift":"lover"},{"id":34,"text":"I prefer to be alone studying the things I am passionate about or explaining them to interested individuals.","gift":"erudite"},{"id":35,"text":"I enjoy stewarding and multiplying resources so I can be more generous.","gift":"host"},{"id":36,"text":"My motto could be, \"Good leaders create a vision, articulate the vision, passionately own the vision, and relentlessly drive it to completion.\" - Jack Welch.","gift":"strategist"},{"id":37,"text":"I have a strong inner sense of what is right and wrong.","gift":"catalyst"},{"id":38,"text":"I often notice and move to meet the practical needs in a room before anyone else does.","gift":"servant"},{"id":39,"text":"I have a strong intuition about interpersonal dynamics and work to build bridges between people.","gift":"enthusiast"},{"id":40,"text":"I am fiercely protective of the vulnerable and instinctively shield them from harm.","gift":"lover"},{"id":41,"text":"I am not easily swayed by peer pressure or others' approval, as I have strong convictions and desires.","gift":"erudite"},{"id":42,"text":"I view the resources I have as something I've been entrusted with for the benefit of others.","gift":"host"},{"id":43,"text":"I excel at architecting a long-term plan and then delegating to the right people to bring that vision to reality.","gift":"strategist"},{"id":44,"text":"I am compelled to challenge the status quo and uproot broken systems to achieve radical, not just incremental, transformation.","gift":"catalyst"},{"id":45,"text":"I feel most fulfilled after a hard day of tangible, productive work.","gift":"servant"},{"id":46,"text":"I'm energized by rallying people together, using fun and celebration to build connections and inspire a shared sense of optimism.","gift":"enthusiast"},{"id":47,"text":"I feel most loved when someone listens to me with their whole heart and understands my feelings.","gift":"lover"},{"id":48,"text":"I feel most loved when someone engages me in a deeply intellectual conversation.","gift":"erudite"},{"id":49,"text":"I constantly am thinking about how myself and others can engage in wise financial stewardship.","gift":"host"}],"forcedChoice":[{"id":50,"stem":"I am more driven to...","a":"Challenge a broken system to get to the truth.","b":"Diligently complete the tasks needed to keep the current system running.","giftA":"catalyst","giftB":"servant"},{"id":51,"stem":"I am more driven to...","a":"Inspire a group of people with a hopeful, positive vision.","b":"Confront a group with an uncomfortable reality that leads to transformation.","giftA":"enthusiast","giftB":"catalyst"},{"id":52,"stem":"I am more driven to...","a":"Speak a hard truth, even if it causes emotional discomfort.","b":"Protect someone's feelings, even if it means avoiding a hard truth.","giftA":"catalyst","giftB":"lover"},{"id":53,"stem":"When leading, my priority is...","a":"Ensuring the team stays the course on a well-thought-out master plan.","b":"Allowing for disruptive innovation that might improve upon the master plan.","giftA":"strategist","giftB":"catalyst"},{"id":54,"stem":"I am more drawn to...","a":"A deep, analytical dive into a complex subject.","b":"A bold, pioneering adventure that challenges my limits.","giftA":"erudite","giftB":"catalyst"},{"id":55,"stem":"My focus is more on...","a":"Wisely stewarding resources to fund a bold, risky, but potentially revolutionary idea or adventure.","b":"Wisely stewarding resources to ensure long-term stability and security.","giftA":"catalyst","giftB":"host"},{"id":56,"stem":"I prefer to show support by...","a":"Cheerfully rallying and encouraging the person.","b":"Practically helping them with their to-do list.","giftA":"enthusiast","giftB":"servant"},{"id":57,"stem":"I believe love is best expressed by...","a":"Providing tangible help and practical solutions.","b":"Providing a safe, empathetic presence for someone's emotions.","giftA":"servant","giftB":"lover"},{"id":58,"stem":"In a group project, I focus on...","a":"The long-term vision and overall strategy.","b":"The immediate tasks that need to be done right now.","giftA":"strategist","giftB":"servant"},{"id":59,"stem":"I am more likely to be...","a":"Frustrated by inaction and analysis paralysis.","b":"Frustrated by rushed decisions made without thorough research.","giftA":"servant","giftB":"erudite"},{"id":60,"stem":"When giving a gift, I am more concerned with...","a":"Ensuring everyone contributes fairly and the gift is practical.","b":"Ensuring the gift is generous, empowering, and makes the recipient feel cherished.","giftA":"servant","giftB":"host"},{"id":61,"stem":"A healthy relationship requires...","a":"Deep emotional safety and unconditional acceptance.","b":"Uplifting joy and mutual celebration.","giftA":"lover","giftB":"enthusiast"},{"id":62,"stem":"I am more inclined to...","a":"Let my decisions be guided by the emotional needs of the people involved.","b":"Let my decisions be guided by the objective goals of the plan.","giftA":"lover","giftB":"strategist"},{"id":63,"stem":"My approach to problems is more...","a":"Analytical and logical, based on verifiable facts.","b":"Empathetic and intuitive, based on people's feelings.","giftA":"erudite","giftB":"lover"},{"id":64,"stem":"When considering a large donation, I prioritize...","a":"The immediate emotional relief and comfort it will bring to an individual.","b":"The long-term strategic impact and stewardship of the organization receiving it.","giftA":"lover","giftB":"host"},{"id":65,"stem":"I am more energized by...","a":"Creating a detailed, systematic plan to achieve a goal.","b":"Inspiring and rallying a team towards a shared objective.","giftA":"strategist","giftB":"enthusiast"},{"id":66,"stem":"I find it more important to be...","a":"Intellectually rigorous and precise.","b":"Relationally warm and encouraging.","giftA":"erudite","giftB":"enthusiast"},{"id":67,"stem":"When planning an event, I focus more on...","a":"The relational atmosphere and ensuring people have fun and connect.","b":"The budget and resources, ensuring a high-quality experience through wise stewardship.","giftA":"enthusiast","giftB":"host"},{"id":68,"stem":"My leadership style is more focused on...","a":"Architecting brilliant, long-term systems and plans.","b":"Patiently mentoring individuals to help them master a subject.","giftA":"strategist","giftB":"erudite"},{"id":69,"stem":"I would rather...","a":"Build a detailed budget and investment plan.","b":"Build a comprehensive research paper with extensive citations.","giftA":"host","giftB":"erudite"},{"id":70,"stem":"When making a big decision, I trust...","a":"A strategic plan that lays out the path to a future goal.","b":"A prudent financial plan that ensures resources are used wisely.","giftA":"strategist","giftB":"host"}],"scenarios":[{"id":1,"stem":"A volunteer project you are on is missing deadlines and team morale is plummeting.","options":["Call an emergency meeting to re-architect the master plan, clarify the vision, and re-delegate tasks.","Privately check in with each team member to see how they are feeling, creating a safe space for them to voice concerns.","Find the biggest practical bottleneck and just start doing the work yourself to get momentum going again.","Directly confront the unspoken issue you believe is causing the failure, pushing for honesty to clear the air."],"gifts":["strategist","lover","servant","catalyst"]},{"id":2,"stem":"A close friend is devastated after being laid off from their job.","options":["Immediately start reminding them of their strengths, telling them this is a setup for a comeback, and painting a positive picture of their future.","Offer a significant and thoughtful financial gift to cover their expenses for a month, empowering them to search for a new job without stress.","Spend hours with them researching the job market, analyzing their resume, and helping them build a logical, data-driven plan for their job search.","Sit with them in their grief, listen without judgment, and let them know you are there for them no matter what, validating their feelings of loss and fear."],"gifts":["enthusiast","host","erudite","lover"]},{"id":3,"stem":"You are on the planning committee for a large community-wide charity event.","options":["Take charge of the budget and fundraising, ensuring every dollar is used wisely to create a high-quality, memorable, and generous experience.","Volunteer to be the MC or lead the welcoming committee, focusing on creating a fun, high-energy, and relational atmosphere.","Take on the role of overall event coordinator, developing the master timeline, defining roles for all teams, and making sure the event achieves its objective.","Sign up for the setup and teardown crew, quietly ensuring all the practical, hands-on work gets done with excellence."],"gifts":["host","enthusiast","strategist","servant"]},{"id":4,"stem":"You receive an unexpected financial windfall of $5,000.","options":["Use it to fund a bold, adventurous trip, or invest it in a high-risk, high-reward idea you believe in.","Put it toward a major long-term goal (like a down payment or a business plan), allocating it according to your life strategy.","Immediately think of a person or cause that could benefit and give a generous, empowering gift.","Spend it on a fantastic party or group vacation to create a lasting, joyful memory with the people you love."],"gifts":["catalyst","strategist","host","enthusiast"]},{"id":5,"stem":"You discover that a long-standing policy in your church or workplace is quietly hurting the very people it was meant to serve.","options":["Name the problem openly and press leadership for immediate, meaningful change, even if it ruffles feathers.","Quietly begin helping the people affected in practical, tangible ways while the debate plays out.","Research the policy's history and gather the data needed to build a careful, well-documented case for reform.","Seek out those who have been hurt, listen to their stories, and make sure no one carries the pain alone."],"gifts":["catalyst","servant","erudite","lover"]},{"id":6,"stem":"Your team is asked to launch a brand-new initiative from scratch, with wide freedom in how to begin.","options":["Challenge the assumptions behind the old way of doing things and cast a bold, disruptive vision for what this could become.","Study how others have done it—gathering research, best practices, and lessons learned before anything is decided.","Architect the master plan: phases, roles, milestones, and a clear picture of success at the end.","Take charge of resourcing it—securing the budget, space, and supplies so the team launches generously provided for."],"gifts":["catalyst","erudite","strategist","host"]},{"id":7,"stem":"A new family joins your community and seems overwhelmed by the transition.","options":["Show up with practical help: meals, moving boxes, school runs—whatever lightens their load this week.","Welcome them warmly, introduce them to everyone, and speak hope and excitement over their new chapter.","Make unhurried space to hear their story and keep checking in on how they are really doing.","Patiently orient them—explaining how everything works and thoroughly answering every question they have."],"gifts":["servant","enthusiast","lover","erudite"]}],"giftMax":{"catalyst":68,"servant":68,"enthusiast":68,"lover":68,"strategist":68,"erudite":68,"host":68}};
window.LOW_GIFTS = {"catalyst": {"struggle": "With the Catalyst's fire burning low, you rarely feel an inner demand to confront what is broken. You may tolerate dysfunctional systems and unspoken problems far longer than is healthy, keep the peace when the moment calls for holy disruption, and feel blindsided when change finally forces itself on you. Necessary conflict can feel like failure rather than faithfulness, so hard conversations get postponed until they become harder ones.", "friction": "People who lead with Prophecy can feel overwhelming to you. Their directness lands like an attack and their urgency like recklessness, and you may quietly write them off as harsh—while they read your patience as complicity with what is broken. When they press for the truth behind a problem, you may hear accusation where they intend rescue.", "bridges": ["When a Catalyst confronts, listen for the love of truth underneath the heat—ask “What are you seeing that I’m not?” before defending.", "Practice naming one broken thing out loud each week; borrowed courage grows.", "Don’t ask a Catalyst to soften the message—ask them to help you build what should replace the broken thing."]}, "servant": {"struggle": "With Service running quiet, practical needs don’t call out to you the way they do to others. Tasks pile up or drift to whoever seems willing, the logistics beneath every good idea get underestimated, and the invisible labor that keeps your home, team, or church running can go unnoticed until it stops. You may carry a reputation for being above the mundane that quietly costs you trust.", "friction": "People who lead with Service often feel unseen around you. Your talk-first instinct frustrates their do-first nature; they feel used when their help is assumed and unthanked, while you may find their focus on tasks small when bigger things are on the table. Your unfinished commitments read to them as broken promises.", "bridges": ["Thank the Servant specifically—name the task, not just the person.", "Before casting the next vision, finish one tangible thing you said you’d do.", "Ask “What needs doing?” and take a visible piece of it yourself."]}, "erudite": {"struggle": "With the Erudite’s hunger dimmed, deep study rarely feels worth the time. You may build strong opinions on thin foundations, decide from intuition alone, and grow impatient with the slow work of truly understanding something. That leaves you vulnerable to shallow answers and confident errors—and prone to repeating problems that an evening of honest study would have prevented.", "friction": "People who lead with Teaching can exhaust you. Their questions feel like doubt, their precision like pedantry, their “let me research it” like delay. Meanwhile they experience your speed as carelessness and your certainty as unearned. Conversations stall when nuance—their native language—gets waved away.", "bridges": ["Bring an Erudite into decisions early, not for rubber-stamping afterward.", "Let them fully vet one significant choice each season—and notice what it saves you.", "Ask “What am I missing?” and genuinely wait for the answer."]}, "enthusiast": {"struggle": "With Encouragement running low, affirmation isn’t your reflex. Relationships can run on function rather than celebration, wins slip past unmarked, and the people closest to you may quietly wonder whether you notice them at all. Without a native supply of hope, setbacks weigh heavier and vision is harder to sustain—for you and for anyone following you.", "friction": "People who lead with Encouragement may strike you as noisy or excessive, and their need for affirmation can feel needy. But your reserve reads to them as disapproval, and they wilt in ways you don’t intend. When they celebrate you, you may deflect—which lands as rejection of the very gift they most love to give.", "bridges": ["Name one strength out loud, per person, per gathering. It will feel like too much; it isn’t.", "Receive an Enthusiast’s praise with a simple thank-you instead of a deflection.", "Let celebration count as real work—it is how belonging gets built."]}, "host": {"struggle": "With Giving quiet in you, resources feel like background details rather than ministry. Generosity happens in bursts instead of rhythms, margins and provision go unplanned, and hospitality can feel like a chore—so gathering people defaults to somebody else. Opportunities that needed seed money, a meal, or an open home pass by unclaimed.", "friction": "People who lead with Giving can seem preoccupied with money, logistics, and stewardship, and their carefulness may read to you as stinginess. But your improvidence genuinely stresses them, and when their quiet provision goes unnoticed they feel taken for granted. Asking them to “just trust” without a plan asks them to violate their design.", "bridges": ["Honor stewardship as a spiritual gift, not accounting—thank the Host for what their planning made possible.", "Schedule one act of intentional generosity each month so giving doesn’t depend on mood.", "Invite a Host to build your budget or event plan with you—and watch the anxiety drop."]}, "strategist": {"struggle": "With Leadership’s long view dimmed, the horizon blurs. Seasons turn busy but directionless, goals drift, and you can wake up wondering how you ended up here. Other people’s plans feel confining, so you improvise—and some of those improvisations become messes a simple map would have prevented. Follow-through on multi-step commitments is the quiet casualty.", "friction": "People who lead with Leadership can feel controlling to you—their structures like cages, their questions about “the plan” like tests you didn’t study for. Meanwhile your spontaneity registers to them as a threat to the mission, and your last-minute pivots undo work they invested in. They don’t need you to become them; they need warning before you swerve.", "bridges": ["Give Strategists the courtesy of a heads-up before changing course.", "Borrow their gift: set one 90-day goal and let them help you sequence it.", "Ask “Where is this going?” before you start—then actually aim."]}, "lover": {"struggle": "With Mercy running quiet, the emotional current of a room flows beneath your notice. You reach for solutions when people need presence, miss the wound behind the behavior, and can leave vulnerable people guarded around you without knowing why. Your own feelings, left unprocessed, tend to leak out sideways as irritation or withdrawal.", "friction": "People who lead with Mercy may seem inefficient to you—slow to decide, quick to feel, forever circling back to how everyone is doing. But your fixes land on them as dismissal, and your pace tramples places that needed gentleness. They need safety before solutions; you lead with solutions.", "bridges": ["Ask “Do you want comfort or counsel?” before offering either.", "Sit with someone’s pain for five full minutes before solving anything.", "Let a Lover teach you what listening without fixing looks like—then practice on them."]}};
window.INTENSITY = function(score){
  if (score >= 85) return { label: 'Very High', cls: 'vh' };
  if (score >= 61) return { label: 'High', cls: 'h' };
  if (score >= 41) return { label: 'Medium', cls: 'm' };
  if (score >= 16) return { label: 'Low', cls: 'l' };
  return { label: 'Very Low', cls: 'vl' };
};
/* Official scoring (Unified Scoring Instructions), normalized per gift maximum.
   state = { likert: {qid: 1..5}, fc: {qid: 'a'|'b'}, sjt: {sid: {most: idx, least: idx}} } */
window.computeScores = function(state){
  var Q = window.QUESTIONS, ORDER = window.GIFT_ORDER;
  var raw = {}, likertSub = {}, fcSub = {};
  ORDER.forEach(function(g){ raw[g]=0; likertSub[g]=0; fcSub[g]=0; });
  Q.likert.forEach(function(q){
    var r = state.likert[q.id] || 1;
    raw[q.gift] += (r-1); likertSub[q.gift] += (r-1);
  });
  Q.forcedChoice.forEach(function(q){
    var pick = state.fc[q.id];
    if (pick === 'a') { raw[q.giftA] += 4; fcSub[q.giftA] += 4; }
    if (pick === 'b') { raw[q.giftB] += 4; fcSub[q.giftB] += 4; }
  });
  Q.scenarios.forEach(function(s){
    var st = state.sjt[s.id] || {};
    s.gifts.forEach(function(g, idx){
      if (idx === st.most) raw[g] += 4;
      else if (idx === st.least) raw[g] += 0;
      else raw[g] += 1;
    });
  });
  var scores = {};
  ORDER.forEach(function(g){
    scores[g] = Math.max(0, Math.min(100, Math.round(raw[g] / Q.giftMax[g] * 100)));
  });
  var ranked = ORDER.slice().sort(function(a,b){
    return (scores[b]-scores[a]) || (likertSub[b]-likertSub[a]) || (fcSub[b]-fcSub[a]) || (ORDER.indexOf(a)-ORDER.indexOf(b));
  });
  var top3 = ranked.slice(0,3);
  var tieAtCut = scores[ranked[2]] === scores[ranked[3]];
  var arch = window.ARCHETYPES.find(function(a){
    return a.gifts.slice().sort().join() === top3.slice().sort().join();
  });
  return { scores: scores, raw: raw, ranked: ranked, top3: top3,
           archetype: arch ? arch.slug : null, tieAtCut: tieAtCut, date: new Date().toISOString() };
};
